const body = $json.body;
const commandText = body.text || '';
const prUrls = (commandText.match(/https:\/\/bitbucket\.org\/[^\s"<>\n]+\/pull-requests\/\d+/g) || []).map(u => u.replace(/[,;]+$/, ''));
const contextHint = commandText.replace(/https:\/\/bitbucket\.org\/[^\s"<>\n]+\/pull-requests\/\d+/g, '').replace(/[",]/g, '').trim();
const parsedPRs = prUrls.map(url => {
  const match = url.match(/bitbucket\.org\/[^/]+\/([^/]+)\/pull-requests\/(\d+)/);
  if (!match) return null;
  return { repo_slug: match[1], pr_id: match[2], url };
}).filter(Boolean);
if (parsedPRs.length === 0) throw new Error('No valid Bitbucket PR URLs found. Paste one or more Bitbucket PR URLs in the message.');
return [{ json: { source: 'manual', parsed_prs: parsedPRs, context_hint: contextHint, requester: body.user_name || 'support-engineer', channel_id: body.channel_id } }];

const { parsed_prs, context_hint, requester, channel_id } = $input.first().json;
return parsed_prs.map((pr, i) => ({
  json: {
    repo_slug: pr.repo_slug,
    pr_id: pr.pr_id,
    context_hint: context_hint || '',
    requester: requester || 'support-engineer',
    channel_id: channel_id || ''
  },
  pairedItem: { item: 0 }
}));

const allDiffItems = $input.all();
const allOriginals = $('Split PRs').all();
const allMeta = $('Fetch PR Metadata').all();
const allDiffstats = $('Fetch Diffstat').all();
const allCommits = $('Fetch Commits').all();

const prGroup = allDiffItems.map((diffItem, i) => {
  const original = allOriginals[i]?.json || {};
  const prMeta = allMeta[i]?.json || {};
  const diffstatData = allDiffstats[i]?.json || {};
  const commitsData = allCommits[i]?.json || {};
  const diffRaw = diffItem.json.data || '';

  const changedFiles = (diffstatData.values || []).map(f => ({
    path: f.new?.path || f.old?.path || 'unknown',
    status: f.status,
    lines_added: f.lines_added || 0,
    lines_removed: f.lines_removed || 0
  }));

  const commitMessages = (commitsData.values || []).map(c => c.message?.split('\n')[0] || '');
  const diff = String(diffRaw).length > 40000 ? String(diffRaw).substring(0, 40000) + '\n...[truncated]' : String(diffRaw);

  return {
    repo_slug: original.repo_slug,
    pr_id: original.pr_id,
    pr_title: prMeta.title || 'Unknown PR',
    pr_description: prMeta.description || 'No description',
    author: prMeta.author?.display_name || original.requester || 'unknown',
    service_md: 'No SERVICE.md found.',
    changed_files: changedFiles,
    commit_messages: commitMessages,
    diff
  };
});

const first = allOriginals[0]?.json || {};

return [{
  json: {
    branch_slug: 'manual',
    source: 'manual',
    context_hint: first.context_hint || '',
    requester: first.requester || '',
    pr_group: prGroup
  }
}];

const data = $json;
const prs = data.pr_group || [];
const systemPrompt = `You are a senior technical analyst reviewing pull requests to understand their user-facing impact.

Return ONLY a valid JSON object with these fields:
- feature_name: short clear name (3-6 words)
- user_impact: "yes", "no", or "partial"
- what_changed: plain English summary, 2-3 sentences, no jargon
- user_actions: array of strings — things users can now do
- guide_title: user-friendly title for the documentation guide
- complexity: "simple" | "moderate" | "complex"
- affected_panels: array from ["tenant-admin", "ordering", "ops"]

Return ONLY the JSON object. No preamble, no markdown fences.`;
const prContextBlocks = prs.map(pr => {
  const files = (pr.changed_files || []).map(f => `  ${f.status.toUpperCase()}: ${f.path} (+${f.lines_added}/-${f.lines_removed})`).join('
');
  return `=== REPO: ${pr.repo_slug} ===
PR: #${pr.pr_id} — ${pr.pr_title}
Description: ${pr.pr_description}
Author: ${pr.author}
Commits:
${(pr.commit_messages || []).map(m => '  - ' + m).join('
')}
Files Changed:
${files}

Diff:
${pr.diff}
`;
}).join('
---
');
const contextHintBlock = data.context_hint ? `
=== CONTEXT HINT ===
${data.context_hint}
` : '';
const requestBody = JSON.stringify({
  model: 'claude-sonnet-4-6',
  max_tokens: 2048,
  system: systemPrompt,
  messages: [{ role: 'user', content: `${contextHintBlock}
${prContextBlocks}` }]
});
return [{ json: { ...data, _analysis_request: requestBody } }];

const prData = $('Build Analysis Payload').first().json;
const response = $input.first().json;
let analysis;
try {
  const raw = response.content?.[0]?.text || '{}';
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  analysis = JSON.parse(cleaned);
} catch(e) {
  const firstPR = (prData.pr_group || [])[0] || {};
  analysis = { feature_name: firstPR.pr_title || 'Unknown Feature', user_impact: 'unknown', what_changed: 'Analysis parsing failed.', user_actions: [], guide_title: firstPR.pr_title || 'Unknown Feature', complexity: 'moderate', affected_panels: ['tenant-admin'] };
}
return [{ json: { ...prData, analysis } }];

const userAgent = ($json.headers?.['user-agent'] || '').toLowerCase();
if (userAgent.includes('slackbot') || userAgent.includes('slack') || userAgent.includes('bot')) {
  return [];
}

const data = $('Parse Analysis').first().json;
const analysis = data.analysis;
const prs = data.pr_group || [];
const panelToneMap = {
  'tenant-admin': 'Professional but approachable. Audience: merchants and business owners.',
  'ordering': 'Warm, simple, encouraging. Audience: end customers placing orders.',
  'ops': 'Direct and functional. Audience: internal ops team.'
};
const panels = analysis.affected_panels || ['tenant-admin'];
const toneGuidance = panels.map(p => `${p}: ${panelToneMap[p] || 'Professional and clear.'}`).join('
');
const repoSummaries = prs.map(pr => `- ${pr.repo_slug}: ${pr.service_md.split('
').slice(0,3).join(' ')}`).join('
');
const systemPrompt = `You are an expert documentation writer for a quick commerce SaaS platform.

Write a complete user-facing guide in Markdown:

# [Guide Title]

## Overview
2-3 sentences explaining what this feature is and why it exists.

## How to Use It
Numbered step-by-step instructions.

## What You Can Do
Bullet list of capabilities.

## Things to Know
2-3 notes using:
💡 Note: for tips
⚠️ Important: for warnings

Tone guidance:
${toneGuidance}

Rules: NEVER mention code or technical terms. Always write in second person. Output clean Markdown only.`;
const contextHintBlock = data.context_hint ? `Support engineer context: ${data.context_hint}

` : '';
const requestBody = JSON.stringify({
  model: 'claude-sonnet-4-6',
  max_tokens: 4096,
  system: systemPrompt,
  messages: [{ role: 'user', content: `${contextHintBlock}Guide Title: ${analysis.guide_title}

Feature Summary: ${analysis.what_changed}

What users can now do:
${(analysis.user_actions || []).join('
')}

Repositories:
${repoSummaries}

Complexity: ${analysis.complexity}
Affected Panels: ${panels.join(', ')}` }]
});
return [{ json: { ...data, _guide_request: requestBody } }];

const prData = $('Build Guide Payload').first().json;
const response = $input.first().json;
const guideContent = response.content?.[0]?.text || '# Guide generation failed';
const today = new Date().toISOString().split('T')[0];
const docTitle = `[DRAFT] ${prData.analysis.guide_title} — ${today}`;
return [{ json: { ...prData, guide_content: guideContent, doc_title: docTitle } }];
